from flask import Flask, request, jsonify, send_file
from flask_sqlalchemy import SQLAlchemy
from flask_migrate import Migrate
from werkzeug.utils import secure_filename
import os
from datetime import datetime
from threading import Lock

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///videos.db'
app.config['UPLOAD_FOLDER'] = 'uploads/'
app.config['MAX_CONTENT_LENGTH'] = 100 * 1024 * 1024  # 100 MB limit
db = SQLAlchemy(app)
migrate = Migrate(app, db)
lock = Lock()

class Video(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(100), nullable=False)
    filename = db.Column(db.String(100), nullable=False)
    uploaded_at = db.Column(db.DateTime, default=datetime.utcnow)

db.create_all()

@app.route('/upload', methods=['POST'])
def upload_video():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    filename = secure_filename(file.filename)
    file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
    new_video = Video(title=request.form['title'], filename=filename)
    db.session.add(new_video)
    db.session.commit()
    return jsonify({'message': 'Video uploaded successfully', 'video_id': new_video.id}), 201

@app.route('/videos', methods=['GET'])
def list_videos():
    videos = Video.query.all()
    return jsonify([{'id': video.id, 'title': video.title} for video in videos]), 200

@app.route('/video/<int:video_id>', methods=['GET'])
def stream_video(video_id):
    video = Video.query.get_or_404(video_id)
    return send_file(os.path.join(app.config['UPLOAD_FOLDER'], video.filename), as_attachment=False)

@app.route('/video/<int:video_id>/play', methods=['POST'])
def play_video(video_id):
    # Logic to handle play request
    return jsonify({'message': 'Playing video', 'video_id': video_id}), 200

@app.route('/video/<int:video_id>/pause', methods=['POST'])
def pause_video(video_id):
    # Logic to handle pause request
    return jsonify({'message': 'Paused video', 'video_id': video_id}), 200

@app.route('/video/<int:video_id>/seek', methods=['POST'])
def seek_video(video_id):
    position = request.json.get('position')
    # Logic to handle seeking to a specific position
    return jsonify({'message': 'Seeked to position', 'video_id': video_id, 'position': position}), 200

@app.route('/video/<int:video_id>/skip', methods=['POST'])
def skip_video(video_id):
    direction = request.json.get('direction')
    # Logic to handle skipping forwards or backwards
    return jsonify({'message': f'Skipped {direction}', 'video_id': video_id}), 200

if __name__ == '__main__':
    app.run(debug=True)

