from flask import Flask, request, jsonify, send_file
from flask_sqlalchemy import SQLAlchemy
from flask_marshmallow import Marshmallow
from werkzeug.utils import secure_filename
import os
from datetime import datetime

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///videos.db'
app.config['UPLOAD_FOLDER'] = 'uploads/'
app.config['MAX_CONTENT_LENGTH'] = 100 * 1024 * 1024  # 100 MB limit
db = SQLAlchemy(app)
ma = Marshmallow(app)

class Video(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(100), nullable=False)
    filename = db.Column(db.String(100), nullable=False)
    resolution = db.Column(db.String(10), nullable=False)
    uploaded_at = db.Column(db.DateTime, default=datetime.utcnow)

class VideoSchema(ma.SQLAlchemyAutoSchema):
    class Meta:
        model = Video

video_schema = VideoSchema()
videos_schema = VideoSchema(many=True)

@app.route('/upload', methods=['POST'])
def upload_video():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    filename = secure_filename(file.filename)
    resolution = request.form.get('resolution', '720p')
    file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
    new_video = Video(title=filename, filename=filename, resolution=resolution)
    db.session.add(new_video)
    db.session.commit()
    return video_schema.jsonify(new_video), 201

@app.route('/videos', methods=['GET'])
def get_videos():
    videos = Video.query.all()
    return videos_schema.jsonify(videos)

@app.route('/video/<int:id>', methods=['GET'])
def stream_video(id):
    video = Video.query.get_or_404(id)
    return send_file(os.path.join(app.config['UPLOAD_FOLDER'], video.filename), as_attachment=False)

@app.route('/video/<int:id>/pause', methods=['POST'])
def pause_video(id):
    # Placeholder for pause functionality
    return jsonify({'message': 'Video paused'}), 200

@app.route('/video/<int:id>/resume', methods=['POST'])
def resume_video(id):
    # Placeholder for resume functionality
    return jsonify({'message': 'Video resumed'}), 200

@app.route('/video/<int:id>/skip', methods=['POST'])
def skip_video(id):
    # Placeholder for skip functionality
    return jsonify({'message': 'Video skipped'}), 200

@app.route('/video/<int:id>/rewind', methods=['POST'])
def rewind_video(id):
    # Placeholder for rewind functionality
    return jsonify({'message': 'Video rewinded'}), 200

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)

