class VideoPlayer:
    def __init__(self):
        self.video_list = []
        self.current_video_index = 0
        self.is_playing = False
        self.playback_speed = 1.0
        self.video_quality = '720p'

    def add_video(self, video):
        self.video_list.append(video)

    def play(self):
        if self.video_list:
            self.is_playing = True
            print(f"Playing: {self.video_list[self.current_video_index]} at {self.video_quality} quality.")
        else:
            print("No videos to play.")

    def pause(self):
        if self.is_playing:
            self.is_playing = False
            print("Video paused.")
        else:
            print("Video is not currently playing.")

    def stop(self):
        self.is_playing = False
        print("Video stopped.")

    def skip_forward(self):
        if self.current_video_index < len(self.video_list) - 1:
            self.current_video_index += 1
            print(f"Skipped to: {self.video_list[self.current_video_index]}")
        else:
            print("No more videos to skip forward to.")

    def skip_backward(self):
        if self.current_video_index > 0:
            self.current_video_index -= 1
            print(f"Skipped back to: {self.video_list[self.current_video_index]}")
        else:
            print("No more videos to skip backward to.")

    def set_playback_speed(self, speed):
        if speed > 0:
            self.playback_speed = speed
            print(f"Playback speed set to: {self.playback_speed}x")
        else:
            print("Invalid playback speed.")

    def set_video_quality(self, quality):
        valid_qualities = ['144p', '240p', '360p', '480p', '720p', '1080p', '4K']
        if quality in valid_qualities:
            self.video_quality = quality
            print(f"Video quality set to: {self.video_quality}")
        else:
            print("Invalid video quality.")

    def show_video_list(self):
        print("Available videos:")
        for index, video in enumerate(self.video_list):
            print(f"{index + 1}: {video}")

# Example usage
