import requests
from bs4 import BeautifulSoup

def scrape_webpage(url):
    response = requests.get(url)
    if response.status_code == 200:
        soup = BeautifulSoup(response.content, 'html.parser')
        return soup
    else:
        return None

def extract_data(soup):
    data = []
    for item in soup.find_all('div', class_='data-item'):
        title = item.find('h2').text
        description = item.find('p').text
        data.append({'title': title, 'description': description})
    return data

def main():
    url = 'http://example.com/data'
    soup = scrape_webpage(url)
    if soup:
        data = extract_data(soup)
        for entry in data:
            print(f"Title: {entry['title']}, Description: {entry['description']}")
    else:
        print("Failed to retrieve the webpage.")

if __name__ == "__main__":
    main()

import requests
from bs4 import BeautifulSoup

def scrape_web_data(url):
    response = requests.get(url)
    if response.status_code == 200:
        soup = BeautifulSoup(response.content, 'html.parser')
        return soup
    else:
        return None

def extract_information(soup):
    data = {}
    # Example extraction logic
    data['title'] = soup.title.string if soup.title else 'No title found'
    data['headings'] = [h.get_text() for h in soup.find_all(['h1', 'h2', 'h3'])]
    return data

def main():
    url = 'http://example.com'  # Replace with the actual URL
    soup = scrape_web_data(url)
    if soup:
        information = extract_information(soup)
        print(information)
    else:
        print('Failed to retrieve data')

if __name__ == '__main__':
    main()

